mapper.select:
SELECT id, from_user_id, to_user_id, content, is_read, job_id, job_key, create_time FROM chat_message WHERE from_user_id = #{fromUserId} AND to_user_id = #{toUserId} AND content = #{content}
AND job_id = #{jobId}
AND job_id IS NULL
AND job_key = #{jobKey}
AND (job_key IS NULL OR job_key = '')
ORDER BY id DESC LIMIT 1
